// ============================================
// Dashboard Page - Main App View
// ============================================

import React, { useState } from 'react';
import Navbar from '../components/Navbar';
import SearchBar from '../components/SearchBar';
import CurrentWeather from '../components/CurrentWeather';
import Forecast from '../components/Forecast';
import AIInsights from '../components/AIInsights';
import LoadingSpinner from '../components/LoadingSpinner';
import AuthModal from '../components/AuthModal';
import { useWeather } from '../context/WeatherContext';

// Welcome screen when no city is searched yet
const WelcomeScreen = ({ onShowAuth }) => (
  <div className="text-center py-20 animate-fade-in">
    <div className="text-8xl mb-6 animate-pulse-slow">🌍</div>
    <h2 className="text-white text-3xl md:text-4xl font-bold mb-4">
      AI-Powered Weather Insights
    </h2>
    <p className="text-white/60 text-lg max-w-lg mx-auto mb-8 leading-relaxed">
      Search any city to get real-time weather data, 5-day forecast,
      and personalized AI recommendations for food, clothing, safety & activities!
    </p>

    {/* Feature Pills */}
    <div className="flex flex-wrap justify-center gap-3 mb-10">
      {[
        { emoji: '🌡️', text: 'Real-time Weather' },
        { emoji: '📅', text: '5-Day Forecast' },
        { emoji: '🤖', text: 'AI Insights' },
        { emoji: '👗', text: 'Clothing Tips' },
        { emoji: '🥤', text: 'Food & Drink Advice' },
        { emoji: '🛡️', text: 'Safety Alerts' },
      ].map((feature, i) => (
        <span key={i}
          className="glass rounded-full px-4 py-2 text-white text-sm flex items-center gap-2 animate-slide-up"
          style={{ animationDelay: `${i * 0.1}s` }}>
          <span>{feature.emoji}</span>
          <span>{feature.text}</span>
        </span>
      ))}
    </div>

    <p className="text-white/40 text-sm">
      ✨ Login to save favorite cities and get personalized recommendations
    </p>
  </div>
);

const Dashboard = () => {
  const { loading, error, currentWeather, forecast } = useWeather();
  const [showAuth, setShowAuth] = useState(false);

  return (
    <div className="min-h-screen bg-weather-default dark:bg-gradient-to-br dark:from-slate-900 dark:via-blue-950 dark:to-slate-900">
      {/* Animated background blobs */}
      <div className="fixed inset-0 overflow-hidden pointer-events-none">
        <div className="absolute -top-40 -right-40 w-80 h-80 bg-blue-500/20 rounded-full blur-3xl animate-pulse-slow" />
        <div className="absolute -bottom-40 -left-40 w-80 h-80 bg-purple-500/20 rounded-full blur-3xl animate-pulse-slow" style={{ animationDelay: '1s' }} />
        <div className="absolute top-1/2 left-1/2 -translate-x-1/2 -translate-y-1/2 w-96 h-96 bg-indigo-500/10 rounded-full blur-3xl" />
      </div>

      {/* Content */}
      <div className="relative z-10 max-w-7xl mx-auto">

        {/* Navbar */}
        <Navbar onShowAuth={() => setShowAuth(true)} />

        {/* Search Bar */}
        <div className="mt-4 mb-8">
          <SearchBar />
        </div>

        {/* Main Content Area */}
        <div className="px-4 pb-10 space-y-6">

          {/* Error Message */}
          {error && (
            <div className="glass rounded-2xl p-4 text-center animate-fade-in border border-red-500/30 bg-red-500/10">
              <p className="text-red-300 font-medium">⚠️ {error}</p>
              <p className="text-white/40 text-sm mt-1">Please check the city name and try again</p>
            </div>
          )}

          {/* Loading State */}
          {loading && <LoadingSpinner />}

          {/* Weather Data */}
          {!loading && currentWeather && (
            <>
              {/* Current Weather Card */}
              <CurrentWeather />

              {/* Section Label */}
              <div className="flex items-center gap-3">
                <div className="h-px flex-1 bg-white/10" />
                <span className="text-white/50 text-sm font-medium">📅 Forecast</span>
                <div className="h-px flex-1 bg-white/10" />
              </div>

              {/* Forecast Cards */}
              {forecast && <Forecast />}

              {/* Section Label */}
              <div className="flex items-center gap-3 mt-2">
                <div className="h-px flex-1 bg-white/10" />
                <span className="text-white/50 text-sm font-medium">🤖 AI Insights</span>
                <div className="h-px flex-1 bg-white/10" />
              </div>

              {/* AI Insights */}
              <AIInsights />
            </>
          )}

          {/* Welcome Screen (when no data yet) */}
          {!loading && !currentWeather && !error && (
            <WelcomeScreen onShowAuth={() => setShowAuth(true)} />
          )}
        </div>
      </div>

      {/* Auth Modal */}
      {showAuth && <AuthModal onClose={() => setShowAuth(false)} />}
    </div>
  );
};

export default Dashboard;
